import { describe, expect, it } from 'vitest';

import {
  AXIS_SHARD_CAPACITY,
  MAHA_ANCHOR,
  PHYLE_AXIS_COUNT,
  getShardAxis,
  mapToMahaShard,
  resolveMahaPhysicalStationRange,
  resolveMahaShardRoute,
  resolveMahaShardedStations,
} from '../src/amplituhedron-sharding';

describe('Maha-anchored Amplituhedron sharding', () => {
  it('maps u64 prefix hashes into the 21-shard Maha range', () => {
    expect(MAHA_ANCHOR).toBe(21);
    expect(PHYLE_AXIS_COUNT).toBe(3);
    expect(AXIS_SHARD_CAPACITY).toBe(7);

    expect(mapToMahaShard(0n)).toBe(0);
    expect(mapToMahaShard(20n)).toBe(20);
    expect(mapToMahaShard(21n)).toBe(0);
    expect(mapToMahaShard('42')).toBe(0);
    expect(mapToMahaShard('18446744073709551615')).toBe(15);
  });

  it('groups shards into three balanced seven-shard axes', () => {
    expect(getShardAxis(0)).toBe(0);
    expect(getShardAxis(6)).toBe(0);
    expect(getShardAxis(7)).toBe(1);
    expect(getShardAxis(13)).toBe(1);
    expect(getShardAxis(14)).toBe(2);
    expect(getShardAxis(20)).toBe(2);
  });

  it('maps a single physical station to all 21 virtual shards', () => {
    const stations = ['station-0'];

    expect(resolveMahaShardRoute(stations.length, 5n)).toEqual({
      shard: 5,
      start: 0,
      end: 1,
    });
    expect(resolveMahaPhysicalStationRange(stations.length, 0)).toEqual({
      stationIndex: 0,
      shardStart: 0,
      shardEnd: 21,
    });
    expect(resolveMahaShardedStations(stations, 5n)).toEqual(['station-0']);
  });

  it('splits 21 virtual shards across two physical stations as 11/10', () => {
    const stations = ['station-0', 'station-1'];

    expect(resolveMahaPhysicalStationRange(stations.length, 0)).toEqual({
      stationIndex: 0,
      shardStart: 0,
      shardEnd: 11,
    });
    expect(resolveMahaPhysicalStationRange(stations.length, 1)).toEqual({
      stationIndex: 1,
      shardStart: 11,
      shardEnd: 21,
    });
    expect(resolveMahaShardedStations(stations, 9n)).toEqual(['station-0']);
    expect(resolveMahaShardedStations(stations, 10n)).toEqual(['station-0']);
    expect(resolveMahaShardedStations(stations, 11n)).toEqual(['station-1']);
    expect(resolveMahaShardedStations(stations, 20n)).toEqual(['station-1']);
  });

  it('selects one physical station when the cluster has exactly 21 stations', () => {
    const stations = Array.from({ length: MAHA_ANCHOR }, (_, index) => `station-${index}`);

    expect(resolveMahaShardRoute(stations.length, 5n)).toEqual({
      shard: 5,
      start: 5,
      end: 6,
    });
    expect(resolveMahaShardedStations(stations, 5n)).toEqual(['station-5']);
    expect(resolveMahaShardedStations(stations, 26n)).toEqual(['station-5']);
  });

  it('selects the replica slice when station count is a multiple of 21', () => {
    const stations = Array.from({ length: MAHA_ANCHOR * 2 }, (_, index) => `station-${index}`);

    expect(resolveMahaShardRoute(stations.length, 5n)).toEqual({
      shard: 5,
      start: 10,
      end: 12,
    });
    expect(resolveMahaShardedStations(stations, 5n)).toEqual(['station-10', 'station-11']);
    expect(resolveMahaShardedStations(stations, 26n)).toEqual(['station-10', 'station-11']);
  });

  it('maps non-divisor physical meshes onto the 21 virtual shards', () => {
    const stations = ['station-0', 'station-1', 'station-2'];

    expect(resolveMahaShardRoute(stations.length, 5n)).toEqual({
      shard: 5,
      start: 0,
      end: 1,
    });
    expect(resolveMahaPhysicalStationRange(stations.length, 0)).toEqual({
      stationIndex: 0,
      shardStart: 0,
      shardEnd: 7,
    });
    expect(resolveMahaPhysicalStationRange(stations.length, 1)).toEqual({
      stationIndex: 1,
      shardStart: 7,
      shardEnd: 14,
    });
    expect(resolveMahaPhysicalStationRange(stations.length, 2)).toEqual({
      stationIndex: 2,
      shardStart: 14,
      shardEnd: 21,
    });
    expect(resolveMahaShardedStations(stations, 5n)).toEqual(['station-0']);
    expect(resolveMahaShardedStations(stations, 7n)).toEqual(['station-1']);
    expect(resolveMahaShardedStations(stations, 14n)).toEqual(['station-2']);
  });

  it('returns no stations for an empty mesh', () => {
    expect(resolveMahaShardRoute(0, 5n)).toBeNull();
    expect(resolveMahaShardedStations([], 5n)).toEqual([]);
  });
});
